Here's a pattern using `MockHttpMessageHandler` to test async behavior, timeouts, and cancellation:

```csharp
[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHttpMessageHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("http://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsHttpRequestException_OnError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("http://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHttpMessageHandler("data", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnTimeout()
    {
        // Handler that delays longer than the timeout
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler) { Timeout = TimeSpan.FromMilliseconds(50) };
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("http://example.com"));
    }

    // --- Test helpers ---

    private class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode)
        {
            _content = content;
            _statusCode = statusCode;
        }

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            });
        }
    }

    private class DelayedHttpMessageHandler : HttpMessageHandler
    {
        private readonly TimeSpan _delay;
        public DelayedHttpMessageHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            await Task.Delay(_delay, cancellationToken);
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key points:**

- **Mock at `HttpMessageHandler`** level — no need for external mocking libraries.
- **Pre-cancelled tokens** verify cancellation is forwarded correctly.
- **`HttpClient.Timeout`** triggers `TaskCanceledException` just like cancellation, so the timeout test validates that the delay handler's token gets cancelled by the client's internal timer.
- All tests are truly async (`async Task`) — never use `.Result` or `.Wait()` in MSTest async tests.
